"use client";

import {
  useEffect,
  useRef,
  type ChangeEvent,
  type FormEvent,
  type KeyboardEvent,
} from "react";
import Button from "@/components/primitives/Button";
import Cluster from "@/components/primitives/Cluster";

const MAX_LEN = 4000;
const MAX_ROWS = 6;

type ChatInputProps = {
  value: string;
  onChange: (next: string) => void;
  onSubmit: () => void;
  onStop?: () => void;
  isStreaming: boolean;
};

export default function ChatInput({
  value,
  onChange,
  onSubmit,
  onStop,
  isStreaming,
}: ChatInputProps) {
  const textareaRef = useRef<HTMLTextAreaElement | null>(null);
  const charCount = value.length;
  const trimmed = value.trim();
  const canSubmit = !isStreaming && trimmed.length > 0 && charCount <= MAX_LEN;

  useEffect(() => {
    const ta = textareaRef.current;
    if (!ta) return;
    ta.style.height = "auto";
    // Cap auto-grow at MAX_ROWS lines; beyond that the textarea scrolls.
    const styles = window.getComputedStyle(ta);
    const lineHeight = parseFloat(styles.lineHeight) || 0;
    const padTop = parseFloat(styles.paddingTop) || 0;
    const padBottom = parseFloat(styles.paddingBottom) || 0;
    const borderTop = parseFloat(styles.borderTopWidth) || 0;
    const borderBottom = parseFloat(styles.borderBottomWidth) || 0;
    const cap =
      lineHeight * MAX_ROWS + padTop + padBottom + borderTop + borderBottom;
    const next = Math.min(ta.scrollHeight, cap || ta.scrollHeight);
    ta.style.height = `${next}px`;
  }, [value]);

  function handleChange(e: ChangeEvent<HTMLTextAreaElement>) {
    const next = e.target.value.slice(0, MAX_LEN);
    onChange(next);
  }

  function handleKeyDown(e: KeyboardEvent<HTMLTextAreaElement>) {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      if (canSubmit) onSubmit();
    }
  }

  function handleSubmit(e: FormEvent<HTMLFormElement>) {
    e.preventDefault();
    if (isStreaming) {
      if (onStop) onStop();
      return;
    }
    if (canSubmit) onSubmit();
  }

  function handleStopClick() {
    if (onStop) onStop();
  }

  const overLimit = charCount > MAX_LEN;

  return (
    <form className="chat-input" onSubmit={handleSubmit} aria-label="Chat input">
      <label htmlFor="chat-input-field" className="sr-only">
        Message
      </label>
      <textarea
        id="chat-input-field"
        ref={textareaRef}
        className="chat-input__field"
        rows={2}
        value={value}
        onChange={handleChange}
        onKeyDown={handleKeyDown}
        placeholder="Ask anything about my work or thinking…"
        maxLength={MAX_LEN}
        disabled={isStreaming}
      />
      <Cluster gap={2} justify="space-between">
        {isStreaming ? (
          <Button
            type="button"
            variant="ghost"
            tone="neutral"
            onClick={handleStopClick}
            disabled={!onStop}
            className="chat-input__send"
          >
            stop
          </Button>
        ) : (
          <Button
            type="submit"
            variant="solid"
            tone="accent"
            disabled={!canSubmit}
            className="chat-input__send"
          >
            ask
          </Button>
        )}
        <span
          className={
            "chat-input__count" +
            (overLimit ? " chat-input__count--over" : "")
          }
          aria-live="polite"
        >
          {charCount} / {MAX_LEN}
        </span>
      </Cluster>
    </form>
  );
}

