1	/* ---------------------------------------------------------------------------
2	 * ChatMessageList — suite 19/P01 (rendering) + 19/P05 (autoscroll + jump)
3	 * Renders the message stream and manages scroll behaviour:
4	 *   - autoscroll to bottom on new tokens when the user is "anchored" near
5	 *     the bottom of the viewport (within AUTOSCROLL_PX),
6	 *   - pause autoscroll once the user scrolls up past that threshold and
7	 *     surface a floating "↓ jump to bottom" button to resume.
8	 * --------------------------------------------------------------------------- */
9	
10	"use client";
11	
12	import {
13	  useCallback,
14	  useEffect,
15	  useLayoutEffect,
16	  useRef,
17	  useState,
18	} from "react";
19	
20	import type { ClientChatMessage } from "@/lib/llm/chatTypes";
21	import Message from "./Message";
22	import RetryAffordance from "./RetryAffordance";
23	import type { CitationItem } from "./Citation";
24	
25	const AUTOSCROLL_PX = 60;
26	
27	export type ChatMessage = ClientChatMessage;
28	
29	type ChatMessageListProps = {
30	  messages?: ClientChatMessage[];
31	  lastError?: string;
32	  onRetry?: () => void;
33	  /**
34	   * Optional resolver to enrich a stored Citation (id/chunkId/snippet)
35	   * with the public-facing CitationItem fields (path/heading/etc.) the
36	   * Message component expects. When omitted, citations render with the
37	   * minimum metadata available.
38	   */
39	  resolveCitation?: (
40	    c: { id: string; chunkId: string; snippet: string },
41	  ) => CitationItem;
42	};
43	
44	function defaultResolveCitation(c: {
45	  id: string;
46	  chunkId: string;
47	  snippet: string;
48	}): CitationItem {
49	  const path = c.chunkId.split("#")[0] ?? c.chunkId;
50	  return { id: c.id, chunkId: c.chunkId, snippet: c.snippet, path };
51	}
52	
53	function isAnchoredToBottom(el: HTMLElement): boolean {
54	  const distance = el.scrollHeight - el.clientHeight - el.scrollTop;
55	  return distance <= AUTOSCROLL_PX;
56	}
57	
58	export default function ChatMessageList({
59	  messages = [],
60	  lastError,
61	  onRetry,
62	  resolveCitation = defaultResolveCitation,
63	}: ChatMessageListProps) {
64	  const containerRef = useRef<HTMLDivElement | null>(null);
65	  // "Anchored": user is at (or within AUTOSCROLL_PX of) the bottom. While
66	  // anchored, new tokens cause smooth autoscroll. As soon as the user
67	  // scrolls up past the threshold, this flips false and the jump button
68	  // becomes visible until they return.
69	  const [anchored, setAnchored] = useState(true);
70	  const anchoredRef = useRef(true);
71	  anchoredRef.current = anchored;
72	
73	  const scrollToBottom = useCallback((smooth: boolean) => {
74	    const el = containerRef.current;
75	    if (!el) return;
76	    el.scrollTo({
77	      top: el.scrollHeight,
