20	
21	export type ChatMetaPayload = {
22	  citations: { id: string; chunkId: string; snippet: string }[];
23	  usage: { inputTokens?: number; outputTokens?: number };
24	  retrievedCount: number;
25	};
26	
27	export type ChatErrorBody = {
28	  error: string;
29	  detail?: string;
30	};
31	
32	/* ---------------------------------------------------------------------------
33	 * Client-side types — used by the useChat hook and chat UI.
34	 * --------------------------------------------------------------------------- */
35	
36	export type Citation = {
37	  id: string;
38	  chunkId: string;
39	  snippet: string;
40	};
41	
42	export type ChatMessageStatus = "complete" | "streaming" | "error";
43	
44	export type ClientChatMessage = {
45	  id: string;
46	  role: "user" | "assistant";
