type ServerMessage = { role: "user" | "assistant"; content: string };

type RateLimitedBody = {
  error?: string;
  detail?: string;
  retryAfterSeconds?: number;
};

function friendlyErrorForStatus(
  status: number,
  body: RateLimitedBody | undefined,
): string {
  if (status === 400) {
    return "Hmm, the request didn't validate. Try shortening your question.";
  }
  if (status === 429) {
    const seconds =
      typeof body?.retryAfterSeconds === "number" && body.retryAfterSeconds > 0
        ? body.retryAfterSeconds
        : 0;
    const minutes = Math.max(1, Math.ceil(seconds / 60));
    return `You've hit the per-hour limit (resets in ${minutes} minute${
      minutes === 1 ? "" : "s"
    }). Try again then.`;
  }
  if (status === 502 || status === 503) {
    return "The LLM service is unreachable right now. Try again in a moment.";
  }
  if (typeof body?.detail === "string" && body.detail) {
    return body.detail;
  }
  return `request failed (${status})`;
}

