  const clear = useCallback(() => {
    if (abortRef.current) {
      abortRef.current.abort();
      abortRef.current = null;
    }
    setMessages([]);
    setStatus("idle");
    setLastError(undefined);
    lastUserTextRef.current = null;
    clearHistoryStorage();
  }, []);

  const stopStreaming = useCallback(() => {
    const ctrl = abortRef.current;
    if (!ctrl) return;
    ctrl.abort();
    abortRef.current = null;
    setStatus("idle");
  }, []);

  return {
    messages,
    status,
    submit,
    retry,
    clear,
    stopStreaming,
    lastError,
    persist,
    setPersist,
  };
}

